  keys: List<VerificationKeyHash>,
  threshold: Int,
}

validator multisig {
  spend(
    datum: Option<Datum>,
    _redeemer: Void,
    _own_ref: transaction.OutputReference,
    self: Transaction,
  ) -> Bool {
    when datum is {
      Some(d) ->
        list.count(d.keys, fn(k) { list.has(self.extra_signatories, k) }) >= d.threshold
      None -> False
    }
  }
}

