use cardano/transaction.{Transaction}
use cardano/assets
use aiken/collection/list

validator total_lovelace {
  spend(
    _datum: Option<Void>,
    _redeemer: Void,
    _own_ref: transaction.OutputReference,
    self: Transaction,
  ) -> Bool {
    let amounts = list.map(self.outputs, fn(o) { assets.lovelace_of(o.value) })
    let total = list.foldl(amounts, 0, fn(acc, x) { acc + x })
    total >= 10_000_000
  }
}

use cardano/transaction.{Transaction, OutputReference, InlineDatum}
use aiken/collection/list

pub type OracleDatum {
  price: Int,
}

pub type Redeemer {
  claimed_price: Int,
}

validator price_check {
  spend(
    _datum: Option<Data>,
    redeemer: Redeemer,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    let oracle_price =
      list.foldl(
        self.reference_inputs,
        None,
        fn(input, acc) {
          when input.output.datum is {
            InlineDatum(raw) -> {
              expect oracle: OracleDatum = raw
              Some(oracle.price)
            }
            _ -> acc
          }
        },
      )
    when oracle_price is {
      Some(p) -> redeemer.claimed_price == p
      None -> False
    }
  }
}

