use cardano/transaction.{OutputReference, Transaction}
use aiken/collection/list
use aiken/crypto.{VerificationKeyHash}
use cardano/address.{Credential}

pub type Datum {
  recipient: VerificationKeyHash,
}

validator single_output {
  spend(
    datum: Option<Datum>,
    _redeemer: Void,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    when datum is {
      Some(d) -> {
        let count =
          list.foldl(
            self.outputs,
            0,
            fn(o, acc) {
              when o.address.payment_credential is {
                Credential.VerificationKey(vk) ->
                  if vk == d.recipient {
                    acc + 1
                  } else {
                    acc
                  }
                _ -> acc
              }
            },
          )
        count == 1
      }
      None -> False
    }
  }
}

