use cardano/transaction.{InlineDatum, OutputReference, Transaction}
use aiken/collection/list
use aiken/crypto.{VerificationKeyHash}

pub type GovConfig {
  members: List<VerificationKeyHash>,
  threshold: Int,
}

validator governance {
  spend(
    _datum: Option<Void>,
    _redeemer: Void,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    let config =
      list.foldl(
        self.reference_inputs,
        None,
        fn(input, acc) {
          when input.output.datum is {
            InlineDatum(raw) -> {
              expect cfg: GovConfig = raw
              Some(cfg)
            }
            _ -> acc
          }
        },
      )
    when config is {
      Some(cfg) -> {
        let sig_count =
          list.foldl(
            cfg.members,
            0,
            fn(m, acc) {
              if list.has(self.extra_signatories, m) {
                acc + 1
              } else {
                acc
              }
            },
          )
        sig_count >= cfg.threshold
      }
      None -> False
    }
  }
}

