pub type FeeConfig {
  min_output_lovelace: Int,
}

validator fee_enforce {
  withdraw(
    _redeemer: Void,
    _account: Credential,
    self: Transaction,
  ) -> Bool {
    let fee_cfg =
      list.foldl(
        self.reference_inputs,
        None,
        fn(input, acc) {
          when input.output.datum is {
            InlineDatum(raw) -> {
              expect cfg: FeeConfig = raw
              Some(cfg.min_output_lovelace)
            }
            _ -> acc
          }
        },
      )
    when fee_cfg is {
      Some(min_ada) ->
        list.all(
          self.outputs,
          fn(o) { assets.lovelace_of(o.value) >= min_ada },
        )
      None -> False
    }
  }
}

